import { useState, useEffect } from 'react';
import Navbar from '../components/Navbar';
import image3 from '../assets/image3.jpg';
import imageesport from '../assets/imageesport.jpg';
import imageccs from '../assets/imageccs.jpg';

function AboutPage() {
  const [theme, setTheme] = useState('dark');

  useEffect(() => {
    const savedTheme = localStorage.getItem('theme') || 'dark';
    setTheme(savedTheme);
    document.body.className = savedTheme === 'light' ? 'light-mode' : '';
  }, []);

  const toggleTheme = () => {
    const newTheme = theme === 'dark' ? 'light' : 'dark';
    setTheme(newTheme);
    localStorage.setItem('theme', newTheme);
    document.body.className = newTheme === 'light' ? 'light-mode' : '';
  };

  return (
    <>
      <Navbar theme={theme} toggleTheme={toggleTheme} />
      <main className="container">
        <section className="about-section">
          <h2>What I Love About Gaming</h2>
          <p>Gaming allows me to escape into creative worlds, challenge my skills, and connect with other players across the globe.</p>
          <img src={image3} alt="Game controller" />
        </section>

        <section className="about-section">
          <h2>My Gaming Journey</h2>
          <p>My gaming journey is more than just a series of matches, it is a testament to the teamwork and community built through local competition in La Union.</p>
          <div className="journey-images">
            <img src={imageesport} alt="Esports competition" />
            <img src={imageccs} alt="Gaming setup" />
          </div>
        </section>

        <footer>
          <p>Contact: gaming@email.com</p>
          <p>© 2026 Gaming Passion</p>
        </footer>
      </main>
    </>
  );
}

export default AboutPage;
